async function tc(t,o="https://snippet.babylonjs.com"){const[r,a]=t.split("#"),e=a?`${o}/${r}/${a}`:`${o}/${r}`,n=await fetch(e);if(!n.ok)throw Error(`NodeMaterial:snippet fetch failed(${n.status})for ${e}`);const i=await n.json();if(!i.jsonPayload)throw Error(`NodeMaterial:snippet "${t}" has no jsonPayload`);const s=JSON.parse(i.jsonPayload);if(!s.nodeMaterial)throw Error(`NodeMaterial:snippet "${t}" has no nodeMaterial`);return JSON.parse(s.nodeMaterial);}export{tc as fetchSnippetSource};